const fs = require('fs');
const path = '/tmp/lead_queue.json';
let q = { cycles: 0, leads: [] };
try { q = JSON.parse(fs.readFileSync(path, 'utf8')); } catch(e) {}

const inds = ['roofing','dental clinic','chiropractor','fitness center','plumber','home renovation','real estate agent','law firm','beauty salon','pest control','landscaping','cleaning service','hvac repair','painting contractor','restaurant','auto repair','movers','electrician','locksmith','massage therapy','daycare','personal trainer','veterinary clinic'];
const locs = ['US','Canada','UK','Australia'];

q.cycles++;
const industry = inds[(q.cycles - 1) % inds.length];
const location = locs[(q.cycles - 1) % locs.length];

fs.writeFileSync(path, JSON.stringify(q));

return {
  industry,
  location,
  cycle: q.cycles,
  query: `${industry} ${location} business email contact`
};

const fs = require('fs');
const html = $json.body || $json.html || '';
const industry = $json.industry || 'general';

// Parse DDG HTML results
const results = [];
const blocks = html.match(/<h2[^>]*class="result__title"[^>]*>[\s\S]*?<\/h2>/gi) || [];
for (const block of blocks) {
  const urlMatch = block.match(/href="(https?:[^"]+)"/);
  const titleMatch = block.match(/<a[^>]*>([\s\S]*?)<\/a>/);
  if (!urlMatch) continue;

  const url = urlMatch[1].replace(/&amp;/g,'&');
  const title = titleMatch ? titleMatch[1].replace(/<[^>]+>/g,'').trim() : '';

  // Find snippet
  const snippetMatch = html.match(new RegExp(url.replace(/[.*+?^${}()|[\]\\]/g, '\\$&').split('?')[0].substring(0,40) + '[\\s\\S]*?<a[^>]*class="result__snippet"[^>]*>([\\s\\S]*?)<\\/a>', 'i'));
  const snippet = snippetMatch ? snippetMatch[1].replace(/<[^>]+>/g,'').trim() : '';

  const biz = {
    business_name: title.split(' - ')[0].split(' | ')[0].trim().replace(/&#?\w+;/g,''),
    website: url.split('?')[0],
    email: '',
    phone: '',
    source: 'duckduckgo',
    industry: industry
  };

  if (!biz.business_name) biz.business_name = url.replace(/https?:\/\/(www\.)?/,'').split('/')[0].replace(/\.com|\.[a-z]{2,4}$/g,'').replace(/-/g,' ').replace(/^./,c=>c.toUpperCase());

  const eMatch = snippet.match(/[\w.+-]+@[\w-]+\.[\w.]+/);
  if (eMatch) { const e=eMatch[0]; if(!['hello@','info@','contact@','support@','admin@','sales@'].some(p=>e.startsWith(p))) biz.email=e; }

  const pMatch = snippet.match(/(\+?\d{1,3}[-.\s]?)?\(?\d{3}\)?[-.\s]?\d{3}[-.\s]?\d{4}/);
  if (pMatch) biz.phone = pMatch[0];

  let s = 30;
  if (biz.email && biz.email.includes('@')) s += 30;
  if (biz.phone && biz.phone.replace(/\D/g,'').length >= 10) s += 20;
  if (biz.website) s += 15;
  biz.score = Math.min(s, 100);

  if (s >= 30) results.push(biz);
}

return { leads: results, industry };

const fs = require('fs');
const path = '/tmp/lead_queue.json';
let q = { cycles: 0, leads: [] };
try { q = JSON.parse(fs.readFileSync(path, 'utf8')); } catch(e) {}

const newLeads = $json.leads || [];
const chains = ['walmart','target','costco','homedepot','lowes','mcdonald','starbucks','subway','domino','kfc','marriott','hilton','best buy','walgreens','cvs','chevron','shell','pizza hut','burger king','taco bell','dunkin','wendy','7-eleven','aldi','lidl','whole foods','publix','safeway','trader joe','tj maxx','macy','nike','adidas','gap','old navy','apple store','verizon','att','tmobile','comcast','xfinity','state farm','geico','allstate','nationwide','yelp','facebook','instagram','linkedin','twitter','amazon','bbb','yellowpages'];

let added = 0;
const existing = new Set(q.leads.map(l => l.business_name?.toLowerCase()));

for (const lead of newLeads) {
  const name = (lead.business_name || '').toLowerCase();
  if (!name || name.length < 3) continue;
  if (chains.some(c => name.includes(c))) continue;
  if (existing.has(name)) continue;

  lead.id = 'lead_' + Math.abs(lead.business_name.split('').reduce((a,c) => a * 31 + c.charCodeAt(0), 0));
  lead.status = 'new';
  lead.added_at = new Date().toISOString();
  q.leads.push(lead);
  existing.add(name);
  added++;
}

q.leads.sort((a,b) => (b.score||0) - (a.score||0));
if (q.leads.length > 200) q.leads = q.leads.slice(0,200);

fs.writeFileSync(path, JSON.stringify(q, null, 2));

return {
  added,
  total_leads: q.leads.length,
  status: `Added ${added} leads (total: ${q.leads.length})`
};
